"package com.example.sophiaquest

import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.activity.enableEdgeToEdge
import androidx.compose.foundation.layout.fillMaxSize
import androidx.compose.material3.MaterialTheme
import androidx.compose.material3.Surface
import androidx.compose.runtime.LaunchedEffect
import androidx.compose.runtime.collectAsState
import androidx.compose.runtime.getValue
import androidx.compose.ui.Modifier
import com.example.sophiaquest.data.SophiaQuestDatabase
import com.example.sophiaquest.data.SophiaQuestRepository
import com.example.sophiaquest.theme.SophiaQuestTheme
import com.example.sophiaquest.utils.AppMusicManager

class MainActivity : ComponentActivity() {
  override fun onCreate(savedInstanceState: Bundle?) {
    super.onCreate(savedInstanceState)

    val database = SophiaQuestDatabase.getDatabase(this)
    val repository = SophiaQuestRepository(database.sophiaQuestDao())

    enableEdgeToEdge()
    setContent {
      val calmMode by repository.getSettingFlow("calm_mode", "false").collectAsState(initial = "false")
      val musicEnabled by repository.getSettingFlow("music_enabled", "true").collectAsState(initial = "true")

      LaunchedEffect(musicEnabled) {
        AppMusicManager.isMusicEnabled = musicEnabled == "true"
        if (musicEnabled != "true") {
          AppMusicManager.stopMusic()
        }
      }

      SophiaQuestTheme(calmMode = calmMode == "true") {
        Surface(modifier = Modifier.fillMaxSize(), color = MaterialTheme.colorScheme.background) {
          MainNavigation()
        }
      }
    }
  }

  override fun onStart() {
    super.onStart()
    AppMusicManager.resumeMusic()
  }

  override fun onStop() {
    super.onStop()
    AppMusicManager.pauseMusic()
  }
}"

